SourceCode.Declaration:
/// <summary>
///    The <c>ETGGMCReportContract</c> class handles the parameters for the Gross Margin by Customers report.
/// </summary>
[DataContractAttribute]
public class ETGGMCReportContract
{
    DateOnhand          PerDate;
    FromDate           fromDate;




}

Method.Source:
[DataMemberAttribute('PerDate'),
SysOperationLabelAttribute(literalStr("To date")),
SysOperationDisplayOrderAttribute('2') ]
public DateOnhand parmPerDate(DateOnhand _PerDate = PerDate)
{
    if (!_PerDate && !PerDate)
    {
        PerDate = systemDateGet();
    }
    else
    {
        PerDate = _PerDate;
    }
    return PerDate;
}

[DataMemberAttribute('FromDate'),
SysOperationLabelAttribute(literalStr("From date")),
SysOperationDisplayOrderAttribute('1') ]
public FromDate parmFromDate(FromDate _fromDate = fromDate)
{
    fromDate = _fromDate;

    return fromDate;
}
